file.content:
recommends: ['spider', 'loom', 'fabricator', 'oculus'],

supportKit: {
  books: {
    plans: { indexes: ['status', 'codex', 'createdAt'] },
  },

  writTypes: [
    { name: 'brief', description: 'A patron brief triggering the planning pipeline' },
    { name: 'brief-ssr', description: 'A patron brief triggering the single-shot reader planning pipeline (experimental)' },
    { name: 'brief-mra', description: 'Experimental brief using merged reader/analyst pipeline' },
  ],

  roles: {
    sage: {
      permissions: ['astrolabe:read', 'astrolabe:write', 'clerk:read'],
      strict: true,
      instructionsFile: 'sage.md',
    },
  } satisfies Record<string, KitRoleDefinition>,

  engines: {
    'astrolabe.plan-init': planInitEngine,
    'astrolabe.inventory-check': inventoryCheckEngine,
    'astrolabe.decision-review': decisionReviewEngine,
    'astrolabe.spec-publish': specPublishEngine,
  },

  rigTemplates: {
    planning: planningTemplate,
    'planning-ssr': planningSsrTemplate,
    'planning-mra': planningMraTemplate,
  },

  rigTemplateMappings: {
    brief: 'astrolabe.planning',
    'brief-ssr': 'astrolabe.planning-ssr',
    'brief-mra': 'astrolabe.planning-mra',
  },

  tools: [
    planShowTool,
    planListTool,
    inventoryWriteTool,
    scopeWriteTool,
    decisionsWriteTool,
    observationsWriteTool,
    specWriteTool,
  ],

