class Transcript:
    jsonl_path: Path
    writ_id: str
    mode: str  # READER, ANALYST, WRITER, READER-ANALYST, or ?
    first_ts: datetime

def iter_transcripts(root: Path, writ_ids: set[str]) -> Iterator[Transcript]:
    """Walk all jsonl files under root, yield ones whose first queue-op matches writ_ids."""
    for project_dir in root.iterdir():
        if not project_dir.is_dir():
            continue
        for jsonl in project_dir.glob("*.jsonl"):
            try:
                with jsonl.open("r") as f:
                    first_line = f.readline()
                if not first_line:
                    continue
                obj = json.loads(first_line)
                if obj.get("type") != "queue-operation":
                    continue
                content = obj.get("content", "")
                m = PLAN_ID_RE.search(content)
                if not m:
                    continue
                writ_id = m.group(1)
                if writ_id not in writ_ids:
                    continue
                mm = MODE_RE.search(content)
                mode = mm.group(1) if mm else "?"
                ts = parse_ts(obj["timestamp"])
                yield Transcript(
                    jsonl_path=jsonl, writ_id=writ_id, mode=mode, first_ts=ts
                )
            except Exception as e:
                print(f"[warn] skipping {jsonl}: {e}", file=sys.stderr)

