def match_transcripts_to_sessions(
    transcripts: list[Transcript], sessions: list[LabSession]
) -> dict[str, Transcript]:
    """Return {lab_session_id: Transcript}. Match by (writ_id, |started_at - first_ts| min)."""
    matches: dict[str, Transcript] = {}
    for sess in sessions:
        candidates = [t for t in transcripts if t.writ_id == sess.writ_id]
        if not candidates:
            continue
        best = min(candidates, key=lambda t: abs((t.first_ts - sess.started_at).total_seconds()))
        delta = abs((best.first_ts - sess.started_at).total_seconds())
        if delta > 60:
            print(
                f"[warn] {sess.session_id}: closest transcript {best.jsonl_path.name} is {delta:.0f}s away — skipping",
                file=sys.stderr,
            )
            continue
        matches[sess.session_id] = best
    return matches

